#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    int fib(int n) {
        if (n <= 1) return n;
        vector<int> memo = {0, 1};
        for (int i = 2; i <= n; i++) {
            memo.push_back(memo[i-1] + memo[i-2]);
        }
        return memo[n];
    }
};

int main() {
    int n;
    cin >> n;
    cout << Solution().fib(n) << endl;
    return 0;
}
